const results = $input.all();
const env = $("Credentials Loop").item.json;

// 1. Validación mejorada: Detecta array vacío [] o array con objeto vacío [{}]
const hasData = results.length > 0 && Object.keys(results[0].json).length > 0;

if (!hasData) {
  return { 
    json: { 
      htmlContent: `<div style="font-family: Arial; padding: 15px; color: green; font-weight: bold;">✅ No hubo errores en el entorno ${env.country} - ${env.entorno}</div>`, 
      channelId: env.channelId 
    } 
  };
}

let html = `<div style="font-family: Arial; border: 1px solid #ccc; padding: 15px;">`;
html += `<p style="font-size: 20px; font-weight: bold; color: #000; margin: 0;">País y Entorno: ${env.country} - ${env.entorno}</p><br>`;

html += `<table border="1" style="border-collapse: collapse; width: 100%; text-align: left;">`;
html += `<tr style="background: #f2f2f2;"><th>CuitId</th><th>RazonSocial</th><th>Concepto</th><th>Procesados</th><th>Aprobados</th><th>Erroneos</th><th>PorcentajeError</th><th>Ponderacion</th></tr>`;

for (const row of results) {
  // 2. Uso de operadores de respaldo para evitar el "undefined"
  html += `<tr>
    <td>${row.json.CuitId ?? ''}</td>
    <td>${row.json.RazonSocial ?? ''}</td>
    <td>${row.json.Concepto ?? ''}</td>
    <td>${row.json.Procesados ?? 0}</td>
    <td>${row.json.Aprobados ?? 0}</td>
    <td>${row.json.Erroneos ?? 0}</td>
    <td>${row.json.PorcentajeError ?? '0%'}</td>
    <td>${row.json.Ponderacion ?? ''}</td>
  </tr>`;
}

html += `</table></div>`;

return { json: { htmlContent: html, channelId: env.channelId } };

